// ============================================================
// PengaturanPage.jsx — Custom category management (CRUD)
// ============================================================
import { useState } from 'react';

export default function PengaturanPage({ data }) {
  const { kategori, setKategori } = data;
  const sumber = kategori?.sumber || [];
  const tujuan = kategori?.tujuan || [];

  const [newSumber, setNewSumber] = useState('');
  const [newTujuan, setNewTujuan] = useState('');
  const [editSumber, setEditSumber] = useState(null); // {idx, val}
  const [editTujuan, setEditTujuan] = useState(null);

  const addSumber = () => {
    const v = newSumber.trim();
    if (!v || sumber.includes(v)) return;
    setKategori({ ...kategori, sumber: [...sumber, v] });
    setNewSumber('');
  };
  const delSumber = (idx) => setKategori({ ...kategori, sumber: sumber.filter((_,i)=>i!==idx) });
  const saveSumber = (idx) => {
    if (!editSumber?.val.trim()) return;
    const updated = [...sumber]; updated[idx] = editSumber.val.trim();
    setKategori({ ...kategori, sumber: updated }); setEditSumber(null);
  };

  const addTujuan = () => {
    const v = newTujuan.trim();
    if (!v || tujuan.includes(v)) return;
    setKategori({ ...kategori, tujuan: [...tujuan, v] });
    setNewTujuan('');
  };
  const delTujuan = (idx) => setKategori({ ...kategori, tujuan: tujuan.filter((_,i)=>i!==idx) });
  const saveTujuan = (idx) => {
    if (!editTujuan?.val.trim()) return;
    const updated = [...tujuan]; updated[idx] = editTujuan.val.trim();
    setKategori({ ...kategori, tujuan: updated }); setEditTujuan(null);
  };

  const KategoriSection = ({ title, desc, items, newVal, setNew, onAdd, onDel, onEdit, editState, setEdit, onSave }) => (
    <div className="card mb-4">
      <div className="section-header">
        <div>
          <div className="section-title">{title}</div>
          <div className="text-muted text-sm" style={{marginTop:3}}>{desc}</div>
        </div>
        <span className="badge blue">{items.length} kategori</span>
      </div>

      {/* Add new */}
      <div style={{display:'flex',gap:8,marginBottom:16}}>
        <input
          className="form-input"
          placeholder={`Nama kategori baru...`}
          value={newVal}
          onChange={e=>setNew(e.target.value)}
          onKeyDown={e=>e.key==='Enter'&&onAdd()}
          style={{flex:1}}
        />
        <button className="btn btn-primary" onClick={onAdd} disabled={!newVal.trim()}>+ Tambah</button>
      </div>

      {/* List */}
      <div className="kategori-list">
        {items.map((item, idx) => (
          <div key={idx} className="kategori-chip">
            {editState?.idx===idx ? (
              <>
                <input
                  className="form-input"
                  style={{height:28,padding:'2px 8px',fontSize:'0.82rem',minWidth:120}}
                  value={editState.val}
                  onChange={e=>setEdit({idx,val:e.target.value})}
                  onKeyDown={e=>{ if(e.key==='Enter') onSave(idx); if(e.key==='Escape') setEdit(null); }}
                  autoFocus
                />
                <button onClick={()=>onSave(idx)} style={{color:'var(--green)',background:'none',border:'none',cursor:'pointer',fontWeight:700,fontSize:'0.9rem'}}>✓</button>
                <button onClick={()=>setEdit(null)} style={{color:'var(--text3)',background:'none',border:'none',cursor:'pointer',fontSize:'0.9rem'}}>✕</button>
              </>
            ) : (
              <>
                <span>{item}</span>
                <button onClick={()=>setEdit({idx,val:item})} style={{color:'var(--accent)',background:'none',border:'none',cursor:'pointer',fontSize:'0.85rem'}}>✎</button>
                <button onClick={()=>onDel(idx)} style={{color:'var(--text3)',background:'none',border:'none',cursor:'pointer',fontSize:'0.9rem'}}
                  title="Hapus">✕</button>
              </>
            )}
          </div>
        ))}
      </div>
    </div>
  );

  return (
    <div className="fade-in">
      <div className="alert warning mb-4">
        ⚠ Menghapus atau mengganti nama kategori tidak mengubah data transaksi yang sudah ada. Hanya mempengaruhi pilihan dropdown saat input baru.
      </div>

      <KategoriSection
        title="Kategori Sumber Pemasukan"
        desc="Dipakai di dropdown 'Sumber Pemasukan' saat tambah transaksi"
        items={sumber}
        newVal={newSumber} setNew={setNewSumber}
        onAdd={addSumber} onDel={delSumber}
        onEdit={()=>{}} editState={editSumber} setEdit={setEditSumber} onSave={saveSumber}
      />

      <KategoriSection
        title="Kategori Tujuan Pengeluaran"
        desc="Dipakai di dropdown 'Tujuan Pengeluaran' saat tambah transaksi"
        items={tujuan}
        newVal={newTujuan} setNew={setNewTujuan}
        onAdd={addTujuan} onDel={delTujuan}
        onEdit={()=>{}} editState={editTujuan} setEdit={setEditTujuan} onSave={saveTujuan}
      />
    </div>
  );
}
